+async fn setup_connector(mock_url: &str) -> BitbucketConnector {
+    let mut c = BitbucketConnector::new();
+    c.handle_configure(json!({ "access_token": "test_oauth_token", "base_url": mock_url }))
+        .await
+        .unwrap();
+    c.handle_handshake(json!({"session_id": "test"}))
+        .await
+        .unwrap();
+    c
