+// -- Collections List --
+
+#[tokio::test]
+async fn collections_list() {
+    let server = MockServer::start().await;
+    Mock::given(method("GET"))
+        .and(path("/collections"))
+        .and(header("Authorization", "Bearer test-token"))
+        .respond_with(ResponseTemplate::new(200).set_body_json(json!({
+            "object": "list",
